import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useWatermarkedVideo } from "@/hooks/useWatermarkedVideo";
import xiaoxiongLogo from "@/assets/xiaoxiong-logo-clean.png";
import { Button } from "@/components/ui/button";
import { Loader2, Check, ArrowRight } from "lucide-react";

const POSTS = [
  {
    postId: "b13d0670-5d8a-4a23-8e4d-83ea580b24ba",
    name: "汤圆",
    originalUrl: "https://tzdgqhwyzsxkxnncgzap.supabase.co/storage/v1/object/public/ai-recipe-videos/generated/cgt-20260223222558-d7jtt-1771856918034.mp4",
  },
  {
    postId: "e8a695df-e5fc-4b17-a405-8be79067fbed",
    name: "黑椒牛柳",
    originalUrl: "https://tzdgqhwyzsxkxnncgzap.supabase.co/storage/v1/object/public/ai-recipe-videos/generated/cgt-20260223222600-76t6j-1771856919075.mp4",
  },
  {
    postId: "b3aeac5e-8a2c-4551-99e8-4442e10a13ef",
    name: "番茄炒蛋",
    originalUrl: "https://tzdgqhwyzsxkxnncgzap.supabase.co/storage/v1/object/public/ai-recipe-videos/generated/cgt-20260223222603-gnns2-1771856913810.mp4",
  },
];

function WatermarkProcessor({ post, onDone }: { post: typeof POSTS[0]; onDone: (url: string) => void }) {
  const { watermarkedUrl, isProcessing, isMp4 } = useWatermarkedVideo(post.originalUrl, xiaoxiongLogo);
  const [uploading, setUploading] = useState(false);
  const [uploaded, setUploaded] = useState(false);
  const [finalUrl, setFinalUrl] = useState("");

  const handleUpload = async () => {
    if (!watermarkedUrl) return;
    setUploading(true);
    try {
      const res = await fetch(watermarkedUrl);
      const blob = await res.blob();
      const ext = isMp4 ? "mp4" : "webm";
      const filePath = `watermarked/${post.postId}-${Date.now()}.${ext}`;
      const { data: uploadData, error } = await supabase.storage
        .from("ai-recipe-videos")
        .upload(filePath, blob, { contentType: blob.type, upsert: false });
      if (error) throw error;
      const { data: urlData } = supabase.storage
        .from("ai-recipe-videos")
        .getPublicUrl(uploadData.path);
      
      // Update the post
      const { error: updateError } = await supabase
        .from("community_posts")
        .update({ video_url: urlData.publicUrl })
        .eq("id", post.postId);
      if (updateError) throw updateError;

      setFinalUrl(urlData.publicUrl);
      setUploaded(true);
      onDone(urlData.publicUrl);
    } catch (e: any) {
      alert("上传失败: " + e.message);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="border rounded-lg p-4 space-y-3">
      <h3 className="font-medium">{post.name} ({post.postId.slice(0, 8)})</h3>
      
      <div className="text-sm text-muted-foreground">
        {isProcessing ? (
          <span className="flex items-center gap-2"><Loader2 className="h-4 w-4 animate-spin" /> 正在合成水印视频...</span>
        ) : watermarkedUrl ? (
          <span className="text-green-600">✓ 水印合成完成</span>
        ) : (
          <span>等待处理...</span>
        )}
      </div>

      {watermarkedUrl && !uploaded && (
        <div className="space-y-2">
          <video src={watermarkedUrl} controls className="w-full max-h-48 rounded" />
          <Button onClick={handleUpload} disabled={uploading} className="w-full">
            {uploading ? <><Loader2 className="h-4 w-4 animate-spin mr-2" /> 上传中...</> : "上传水印视频并更新帖子"}
          </Button>
        </div>
      )}

      {uploaded && (
        <div className="flex items-center gap-2 text-green-600">
          <Check className="h-4 w-4" /> 已更新帖子视频为水印版本
          <span className="text-xs text-muted-foreground ml-2 break-all">{finalUrl.slice(-40)}</span>
        </div>
      )}
    </div>
  );
}

export default function AdminWatermarkTool() {
  const [results, setResults] = useState<Record<string, string>>({});

  return (
    <div className="max-w-2xl mx-auto p-6 space-y-6">
      <h1 className="text-xl font-bold">临时水印工具 - Sam Wang 帖子</h1>
      <p className="text-sm text-muted-foreground">
        每个视频会通过浏览器端合成水印，然后上传到存储并更新帖子的 video_url。
      </p>
      
      {POSTS.map(post => (
        <WatermarkProcessor
          key={post.postId}
          post={post}
          onDone={(url) => setResults(prev => ({ ...prev, [post.postId]: url }))}
        />
      ))}

      {Object.keys(results).length === POSTS.length && (
        <div className="p-4 bg-green-50 rounded-lg text-green-800 dark:bg-green-900/20 dark:text-green-300">
          ✅ 所有 3 个帖子已更新为带水印的视频！可以删除此页面。
        </div>
      )}
    </div>
  );
}
